## Setup ----
# Load or prepare any necessary data for testing
example_path <- testthat::test_path(
  "..",
  "..",
  "inst",
  "examples",
  "catch_at_age_spec_builder.R"
)

## IO correctness ----
test_that("build_fims creates Rcpp modules from a small CatchAtAge spec", {
  #' @description Test that build_fims translates a declarative CatchAtAge spec into linked Rcpp objects.
  spec <- catch_at_age(
    population = population(
      name = "stock",
      ages = 1:4,
      years = 2020:2022,
      growth = ewaa_growth(ages = 1:4, weights = c(0.2, 0.5, 0.9, 1.1)),
      maturity = logistic_maturity(a50 = 3, slope = 1.2),
      recruitment = beverton_holt(
        log_rzero = fixed_effect(log(1000)),
        steepness = fixed_effect(0.75)
      )
    ),
    fleets = list(
      fleet(
        name = "fishery",
        selectivity = logistic_selectivity(a50 = 3, slope = 1.1),
        fishing_mortality = fixed_effect(rep(log(0.1), 3))
      )
    ),
    observations = list(
      observe_landings(
        fleet = "fishery",
        data = c(100, 105, 110),
        distribution = lognormal(sd = 0.2)
      )
    )
  )

  built <- build_fims(spec, create_model = FALSE)

  expect_s3_class(built, "FIMSBuilderResult")
  expect_true(built$model$UsesLikelihoodTerms())
  expect_named(built$fleets, "fishery")
  expect_length(built$observations, 1L)
  expect_length(built$distributions, 1L)
  expect_equal(built$fleets$fishery$GetObservedLandingsDataID(), 1L)
  expect_equal(built$population$GetName(), "stock")

  clear()
})

test_that("clean R CatchAtAge builder example runs end to end", {
  #' @description Test that the clean R CatchAtAge builder example creates mirrored likelihood terms.
  example_env <- new.env(parent = globalenv())

  expect_no_error(sys.source(example_path, envir = example_env))
  expect_s3_class(example_env$built, "FIMSBuilderResult")
  expect_s3_class(example_env$likelihood_terms, "data.frame")
  expect_gt(nrow(example_env$likelihood_terms), 0L)
  expect_true(any(example_env$likelihood_terms[["type"]] == "data"))

  example_text <- readLines(example_path, warn = FALSE)
  expect_false(any(grepl(
    "\\b(set_distribution_links|set_observed_data|methods::new|UseLikelihoodTerms)\\b",
    example_text
  )))

  clear()
})

## Edge handling ----
test_that("build_fims validates builder inputs", {
  #' @description Test that build_fims requires a model spec.
  expect_error(
    build_fims("not a spec"),
    regexp = "`spec` must be a FIMS model spec"
  )
  expect_error(
    build_fims(catch_at_age(
      population = population(
        name = "stock",
        ages = 1:4,
        years = 2020:2022,
        growth = ewaa_growth(1:4, 1:4),
        maturity = logistic_maturity(3, 1),
        recruitment = beverton_holt(1, 0.75)
      )
    ), create_model = NA),
    regexp = "`create_model` must be TRUE or FALSE"
  )
})

## Error handling ----
test_that("build_fims reports unsupported or inconsistent specs", {
  #' @description Test that build_fims reports missing fleet links and unsupported observations.
  spec_missing_fleet <- catch_at_age(
    population = population(
      name = "stock",
      ages = 1:4,
      years = 2020:2022,
      growth = ewaa_growth(1:4, 1:4),
      maturity = logistic_maturity(3, 1),
      recruitment = beverton_holt(1, 0.75)
    ),
    observations = list(
      observe_landings("fishery", c(1, 2, 3), lognormal(sd = 0.2))
    )
  )
  expect_error(
    build_fims(spec_missing_fleet, create_model = FALSE),
    regexp = "No fleet named `fishery` was found"
  )

  spec_bad_data_length <- catch_at_age(
    population = population(
      name = "stock",
      ages = 1:4,
      years = 2020:2022,
      growth = ewaa_growth(1:4, 1:4),
      maturity = logistic_maturity(3, 1),
      recruitment = beverton_holt(1, 0.75)
    ),
    fleets = list(fleet("fishery", logistic_selectivity(3, 1))),
    observations = list(
      observe_index("fishery", c(1, 2), lognormal(sd = 0.2))
    )
  )
  expect_error(
    build_fims(spec_bad_data_length, create_model = FALSE),
    regexp = "Observation data must have length `n_years`"
  )
})
